// Code_Normalize_Manifests (FINAL v2 - minimal schema, enterprise hardening)

const isDate = (s) => /^\d{4}-\d{2}-\d{2}$/.test(String(s || "").trim());
const isHex24 = (s) => /^[0-9a-f]{24}$/i.test(String(s || "").trim());
const toStr = (v) => (v ?? "").toString().trim();

const parseMaxRows = (v) => {
  let n = Number(String(v ?? 20).replace(/[^0-9]/g, ""));
  if (!Number.isFinite(n) || n <= 0) n = 20;
  if (n > 50) n = 50; // AI-SAFE cap
  return n;
};

// Required: token
const token = toStr($json.token);
if (!token) {
  return [{
    json: {
      ok: false,
      error: "token is required (Bearer JWT missing)",
      tokenPresent: false,
      tokenPrefix: null,
    }
  }];
}

const providerId = toStr($json.providerId);
const productId  = toStr($json.productId);

if (!providerId) return [{ json: { ok: false, error: "providerId is required", tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!productId)  return [{ json: { ok: false, error: "productId is required", tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

if (!isHex24(providerId)) return [{ json: { ok: false, error: "providerId must be 24-hex", providerId, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!isHex24(productId))  return [{ json: { ok: false, error: "productId must be 24-hex", productId, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

const dateFrom = toStr($json.dateFrom);
const dateTo   = toStr($json.dateTo || dateFrom);

if (!isDate(dateFrom)) return [{ json: { ok: false, error: "dateFrom must be YYYY-MM-DD", dateFrom, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!isDate(dateTo))   return [{ json: { ok: false, error: "dateTo must be YYYY-MM-DD", dateTo, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

const maxRows = parseMaxRows($json.maxRows);

return [{
  json: {
    ok: true,
    token,
    tokenPresent: true,
    tokenPrefix: token.slice(0, 12),
    providerId,
    productId,
    dateFrom,
    dateTo,
    maxRows
  }
}];

