// Code_AI_SAFE_Reducer_Manifests v3.0
// Basado en estructura REAL confirmada del JSON de Betterez
// Subworkflow: Btz_Rpts_Trip_Manifests_AI_SAFE
// ============================================================

// --- Parámetros del nodo anterior ---
const input = $items("Code_Normalize_Manifests")[0].json;
const maxRows = Number(input.maxRows ?? 20);

// --- Recibir el array directo de la API ---
// La API devuelve: [ { manifest:{...}, tickets:[...] }, ... ]
const raw = $input.first().json;

// Verificar que sea un array válido
if (!Array.isArray(raw) || raw.length === 0) {
  return [{
    json: {
      ok: false,
      params: {
        providerId: input.providerId,
        productId: input.productId,
        dateFrom: input.dateFrom,
        dateTo: input.dateTo,
        maxRows
      },
      mensaje: "No se encontraron manifests para los parámetros indicados.",
      kpis: null,
      top: null
    }
  }];
}

// --- ID corto (últimos 6 caracteres) ---
const toIdShort = (id) => (id ? String(id).slice(-6) : 'N/D');

// --- Acumuladores globales ---
let totalCapacidad = 0;
let totalReservados = 0;
let totalIngresoMicros = 0;
let totalBoletos = 0;

// --- Procesar cada manifest ---
const rowsAll = raw.map((item, idx) => {

  const m = item.manifest || {};
  const tickets = item.tickets || [];
  const legs = m.legs || [];

  // Origen y destino desde legs
  const origen = legs.length > 0 ? legs[0].station : 'N/D';
  const destino = legs.length > 0 ? legs[legs.length - 1].toStation : 'N/D';

  // Ocupación
  const capacidad = m.capacity || 0;
  const reservados = m.totalReserved || 0;
  const pctOcup = capacidad > 0 ? Math.round((reservados / capacidad) * 100) : 0;

  // Ingresos (micros → MXN)
  const ingresoMicros = tickets.reduce((s, t) => s + (t.total || 0), 0);
  const ingresoMXN = +(ingresoMicros / 1000000).toFixed(2);

  // Duración legible
  const durMin = m.duration || 0;
  const duracion = `${Math.floor(durMin/60)}h ${durMin%60}m`;

  // Fecha limpia
  const fecha = (m.date?.value || '').slice(0, 10) || 'N/D';

  // Acumular KPIs
  totalCapacidad += capacidad;
  totalReservados += reservados;
  totalIngresoMicros += ingresoMicros;
  totalBoletos += tickets.length;

  return {
    n: idx + 1,
    idShort: toIdShort(m._id),
    ruta: m.scheduleDisplayName || 'N/D',
    fecha,
    salida: m.time || 'N/D',
    llegada: m.arrivalTime || 'N/D',
    origen,
    destino,
    brand: m.brandName || 'N/D',
    status: m.status || 'N/D',
    capacidad,
    reservados,
    ocupacion: `${pctOcup}%`,
    distKm: m.distance || 0,
    duracion,
    ingresoMXN,
    boletos: tickets.length
  };
});

// --- KPIs globales ---
const ocupGlobal = totalCapacidad > 0
  ? Math.round((totalReservados / totalCapacidad) * 100)
  : 0;

// --- Ordenar por ingreso (mayor primero) y limitar filas ---
const rowsTop = [...rowsAll]
  .sort((a, b) => b.ingresoMXN - a.ingresoMXN)
  .slice(0, maxRows);

// --- Salida final para el AI Agent ---
return [{
  json: {
    ok: true,
    params: {
      providerId: input.providerId,
      productId: input.productId,
      dateFrom: input.dateFrom,
      dateTo: input.dateTo,
      maxRows
    },
    kpis: {
      totalViajes: raw.length,
      totalCapacidad,
      totalReservados,
      ocupacionGlobal: `${ocupGlobal}%`,
      totalBoletos,
      ingresoTotal: `$${(totalIngresoMicros/1000000).toFixed(2)} MXN`
    },
    top: {
      columns: ["n","idShort","ruta","fecha","salida","llegada",
                "origen","destino","brand","status",
                "capacidad","reservados","ocupacion",
                "distKm","duracion","ingresoMXN","boletos"],
      rows: rowsTop
    }
  }
}];

// Code_Return_Error (FINAL)
return [{
  json: {
    ok: false,
    error: $json.error ?? "Normalize failed",
    details: $json
  }
}];

// Final_Output (FINAL) - unified response for ToolWorkflow

const j = $json ?? {};

// If previous node already marked ok:false (Normalize/IF branch)
if (j.ok === false) {
  return [{
    json: {
      ok: false,
      error: j.error ?? "Unknown error",
      details: j.details ?? j,
    }
  }];
}

// If previous node is success but doesn't include ok, force ok:true
return [{
  json: {
    ok: true,
    ...j
  }
}];

const loginData = $('Login_BTZ_Manifests').first().json;
