const http2 = require('http2');

const input = $input.first().json;
const providerId = input.providerId;
const productId  = input.productId;
const dateFrom   = input.dateFrom;
const dateTo     = input.dateTo;
const authHeader = input.authHeader;

const apiPath = '/operations/manifests?providerId=' + encodeURIComponent(providerId) +
  '&productId=' + encodeURIComponent(productId) +
  '&dateFrom='  + encodeURIComponent(dateFrom) +
  '&dateTo='    + encodeURIComponent(dateTo);

const data = await new Promise((resolve, reject) => {

  const client = http2.connect('https://api.betterez.com', {
    settings: { headerTableSize: 65536 }
  });

  client.on('error', (err) => {
    reject(new Error('Client error: ' + err.message));
  });

  const reqHeaders = {
    ':method':       'GET',
    ':path':         apiPath,
    ':authority':    'api.betterez.com',
    ':scheme':       'https',
    'x-api-key':     '8af2a813-c77b-4c2c-90ed-2dab3461242a',
    'authorization': authHeader,
    'accept':        'application/json',
    'user-agent':    'n8n-client/1.0'
  };

  const req = client.request(reqHeaders);
  req.setEncoding('utf8');

  let body = '';
  let statusCode = 0;

  req.on('response', (headers) => {
    statusCode = headers[':status'];
  });

  req.on('data', (chunk) => { body += chunk; });

  req.on('end', () => {
    client.close();
    if (statusCode >= 200 && statusCode < 300) {
      try {
        resolve(JSON.parse(body));
      } catch(e) {
        reject(new Error('JSON parse error: ' + body.slice(0, 300)));
      }
    } else {
      reject(new Error('HTTP ' + statusCode + ': ' + body.slice(0, 300)));
    }
  });

  req.on('error', (err) => {
    client.close();
    reject(new Error('Request error: ' + err.message));
  });

  req.end();
});

const manifests = Array.isArray(data) ? data : (data.results || data.manifests || [data]);
return manifests.map(item => ({ json: item }));

const cp = require('child_process');
const fs = require('fs');

const input = $input.first().json;

fs.writeFileSync('/tmp/btz_token.txt', input.authHeader);

const script = `#!/bin/sh
TOKEN=$(cat /tmp/btz_token.txt)
curl -s --http2 -w "\\nSTATUS:%{http_code}" \\
  -H "x-api-key: 8af2a813-c77b-4c2c-90ed-2dab3461242a" \\
  -H "Authorization: $TOKEN" \\
  -H "Accept: application/json" \\
