`;

fs.writeFileSync('/tmp/btz_call.sh', script);
cp.execSync('chmod +x /tmp/btz_call.sh');

const result = cp.execSync('/tmp/btz_call.sh', {
  maxBuffer: 10 * 1024 * 1024,
  timeout: 30000
}).toString();

// Separar body del status
const parts = result.split('\nSTATUS:');
const body = parts[0].substring(0, 300);
const status = parts[1] ? parts[1].trim() : 'unknown';

return [{ json: { 
  status: status, 
  body_preview: body,
  token_length: input.authHeader.length
}}];

